    sys_getcwd(buf.as_mut_ptr(), buf.len());
    String::from_utf8_lossy(&buf)
        .trim_end_matches('\0')
        .to_string()
}

pub fn shutdown() -> ! {
    sys_shutdown();
    loop {}
}

pub fn flush() {
    sys_flush();
